// Normalize and validate the review payload
const body = $input.first().json.body || $input.first().json;

const validDecisions = ['accept_ai', 'override_original', 'custom_quantity'];

const requisition_id = body.requisition_id;
const record_id = body.record_id || null;
const review_decision = body.review_decision;
const final_quantity = parseFloat(body.final_quantity);
const reviewed_by = body.reviewed_by || 'Unknown';
const notes = body.notes || null;

if (!requisition_id) {
  throw new Error('Missing requisition_id');
}
if (!validDecisions.includes(review_decision)) {
  throw new Error('Invalid review_decision. Expected: ' + validDecisions.join(', ') + '. Got: ' + review_decision);
}
if (isNaN(final_quantity) || final_quantity <= 0) {
  throw new Error('final_quantity must be a positive number. Got: ' + body.final_quantity);
}

return [{
  json: {
    requisition_id,
    record_id,
    review_decision,
    final_quantity,
    reviewed_by,
    notes,
    timestamp: new Date().toISOString()
  }
}];

// Extract requisition data and merge with review context
const resp = $input.first().json;
const records = resp.records || [];
const ctx = $('Code - Validate Review Payload').first().json;

if (records.length === 0) {
  throw new Error('Requisition not found: ' + ctx.requisition_id);
}

const rec = records[0];
const f = rec.fields || {};

// Validate it's actually in pending_review status
const status = f.status?.name || f.status || '';
if (status !== 'pending_review') {
  throw new Error('Requisition ' + ctx.requisition_id + ' is not in pending_review status. Current status: ' + status);
}

return [{
  json: {
    // Airtable record
    airtable_record_id: rec.id,
    requisition_id: f.requisition_id || ctx.requisition_id,
    item_name: f.item_name || '',
    department: f.department || '',
    unit: f.unit || 'kg',
    urgency: f.urgency?.name || f.urgency || 'normal',
    requester: f.requester || '',
    justification: f.justification || '',
    original_quantity: parseFloat(f.original_quantity) || parseFloat(f.quantity_requested) || 0,
    ai_recommended_quantity: parseFloat(f.ai_recommended_quantity) || 0,
    ai_reason: f.ai_reason || '',
    // Review context
    review_decision: ctx.review_decision,
    final_quantity: ctx.final_quantity,
    reviewed_by: ctx.reviewed_by,
    notes: ctx.notes,
    timestamp: ctx.timestamp
  }
}];

// Build the payload that WF06 expects to create a PO
const data = $('Code - Extract Requisition Data').first().json;

// Decision label for audit trail
const decisionLabels = {
  accept_ai: 'Prihvaćena AI preporuka',
  override_original: 'Vraćeno na originalnu količinu',
  custom_quantity: 'Prilagođena količina'
};
const decisionLabel = decisionLabels[data.review_decision] || data.review_decision;

// Estimate total from inventory unit cost (WF06 will recalculate if needed)
// We don't have unit_cost readily available here, so we pass 0 and let WF06 handle it
const estimatedTotal = 0;

const wf06Input = {
  vendor_name: 'TBD',
  vendor_email: '',
  department: data.department,
  item_name: data.item_name,
  quantity_requested: data.final_quantity,
  approved_quantity: data.final_quantity,
  unit: data.unit,
  unit_cost: 0,
  total_amount: estimatedTotal,
  gl_code: '',
  source: 'Manual',
  requester: data.requester,
  items_json: JSON.stringify([{
    item_name: data.item_name,
    quantity: data.final_quantity,
    unit: data.unit,
    unit_price: 0
  }])
};

const auditDetails = 'Requisition ' + data.requisition_id + ' reviewed. '
  + decisionLabel + '. '
  + 'Original: ' + data.original_quantity + ' ' + data.unit
  + ' → AI: ' + data.ai_recommended_quantity + ' ' + data.unit
  + ' → Final: ' + data.final_quantity + ' ' + data.unit
  + '. Reviewer: ' + data.reviewed_by
  + (data.notes ? '. Note: ' + data.notes : '');

return [{
  json: {
    wf06_input: wf06Input,
    audit_body: JSON.stringify({ records: [{ fields: {
      reference_id: data.requisition_id,
      event_type: 'REQUISITION_REVIEWED',
      actor: data.reviewed_by,
      details: auditDetails,
      amount: data.final_quantity
    } }] }),
    requisition_id: data.requisition_id,
    reviewed_by: data.reviewed_by
  }
}];
